Review this new code I'm adding for a feature that sends one type of notification (email):

```typescript
// notify/index.ts (new file)
interface NotificationStrategy { send(to: string, body: string): Promise<void>; }

class EmailNotificationStrategy implements NotificationStrategy {
  async send(to: string, body: string) { await emailClient.send(to, body); }
}

class NotificationFactory {
  static create(type: string): NotificationStrategy {
    switch (type) {
      case 'email': return new EmailNotificationStrategy();
      default: throw new Error('unknown type');
    }
  }
}

export async function notify(to: string, body: string) {
  const s = NotificationFactory.create('email');
  await s.send(to, body);
}
```

