// handlers/users.go (diff)
func ActiveUsers(db *sql.DB) ([]UserDTO, error) {
    rows, _ := db.Query("SELECT id, name FROM users WHERE active = true")
    var out []UserDTO
    for rows.Next() {
        var u UserDTO
        rows.Scan(&u.ID, &u.Name)
        total, _ := orderTotal(db, u.ID) // runs a SELECT per user
        u.OrderTotal = total
        out = append(out, u)
    }
    return out, nil
}
